1	//! tp_pc — parity port of iiac-perf's `tp-pc` bench onto the
2	//! tprobe crate's collection phase.
3	//!
4	//! A dedicated producer thread and a dedicated consumer thread
5	//! trade messages over two `std::sync::mpsc` channels; each
6	//! actor measures its own full loop iteration. Identical loop,
7	//! channels, and band-table output to iiac-perf's `tp-pc`; what
8	//! differs is the recording:
9	//!
10	//! - iiac-perf `tp-pc`: hdrhistogram `record()` per iteration
11	//!   (compress at collection).
12	//! - here: `TProbe` + [`ArrayRecorder`] — one raw-delta store
13	//!   per iteration; the histogram is built *after* the run
14	//!   (analyze off the measured path, per `notes/design.md`).
15	//!
16	//! Run back-to-back with iiac-perf's `tp-pc` on the same cores
17	//! to see the collection-phase cost/benefit.
18	
19	mod band_table;
20	
21	use std::sync::atomic::{AtomicBool, Ordering};
22	use std::sync::{Arc, mpsc};
23	use std::thread;
24	use std::time::Duration;
25	
26	use hdrhistogram::Histogram;
27	use tprobe::{ArrayRecorder, TProbe, ticks};
28	
29	/// Histogram bounds matching iiac-perf's probes: 1..1e12 ticks
30	/// (~250 s at 4 GHz), 3 significant figures.
31	const HIST_HIGH: u64 = 1_000_000_000_000;
32	
33	/// Default per-thread delta capacity: 8 Mi samples (64 MiB).
34	const DEFAULT_CAP: usize = 8 * 1024 * 1024;
35	
36	/// Parsed CLI configuration.
37	struct Cfg {
38	    /// Measured run duration in seconds.
39	    secs: f64,
40	    /// Logical CPUs for (producer, consumer); `None` = unpinned.
41	    cores: [Option<usize>; 2],
42	    /// Per-thread delta-buffer capacity, in samples.
43	    cap: usize,
44	    /// Report raw ticks instead of nanoseconds.
45	    as_ticks: bool,
46	}
47	
48	/// Parse CLI args. `Ok(None)` means `--help` was printed.
49	fn parse_args(mut args: std::env::Args) -> Result<Option<Cfg>, String> {
50	    let mut cfg = Cfg {
51	        secs: 5.0,
52	        cores: [None, None],
53	        cap: DEFAULT_CAP,
54	        as_ticks: false,
55	    };
56	    args.next(); // skip argv[0]
57	    while let Some(arg) = args.next() {
58	        match arg.as_str() {
59	            "--secs" => {
60	                let v = args.next().ok_or("--secs needs a value")?;
61	                cfg.secs = v
62	                    .parse::<f64>()
63	                    .map_err(|e| format!("invalid --secs {v:?}: {e}"))?;
64	            }
65	            "--cores" => {
66	                let v = args.next().ok_or("--cores needs a value, e.g. 0,1")?;
67	                let mut it = v.split(',');
68	                let (Some(a), Some(b), None) = (it.next(), it.next(), it.next()) else {
69	                    return Err(format!("--cores wants exactly two ids, got {v:?}"));
70	                };
71	                cfg.cores = [
72	                    Some(a.parse().map_err(|e| format!("invalid core {a:?}: {e}"))?),
73	                    Some(b.parse().map_err(|e| format!("invalid core {b:?}: {e}"))?),
74	                ];
75	            }
76	            "--cap" => {
77	                let v = args.next().ok_or("--cap needs a value")?;
78	                cfg.cap = v
79	                    .parse::<usize>()
80	                    .map_err(|e| format!("invalid --cap {v:?}: {e}"))?;
81	            }
82	            "--ticks" | "-t" => cfg.as_ticks = true,
83	            "--help" | "-h" => {
84	                println!(
85	                    "usage: tp_pc [--secs F] [--cores A,B] [--cap N] [--ticks]\n\
86	                     \n\
87	                     defaults: --secs 5.0, unpinned, --cap {DEFAULT_CAP} (per thread)"
88	                );
89	                return Ok(None);
90	            }
91	            other => return Err(format!("unknown arg {other:?} (try --help)")),
92	        }
93	    }
94	    Ok(Some(cfg))
95	}
96	
97	/// Pin the current thread to `logical_cpu`. No-op if `None`.
98	fn pin_current(logical_cpu: Option<usize>) {
99	    let Some(target) = logical_cpu else { return };
100	    core_affinity::set_for_current(core_affinity::CoreId { id: target });
101	}
102	
103	/// Build a probe over a preallocated, pre-faulted delta buffer,
104	/// so first-touch page faults don't land inside the measured
105	/// loop.
106	fn make_probe(name: &'static str, cap: usize) -> TProbe<ArrayRecorder<Vec<u64>>> {
107	    let mut buf = vec![0u64; cap];
108	    // Touch one u64 per 4 KiB page.
109	    buf.iter_mut().step_by(512).for_each(|v| *v = 1);
110	    std::hint::black_box(&mut buf);
111	    TProbe::new(name, ArrayRecorder::new(buf))
112	}
113	
114	/// Analysis + presentation, after the run: build the histogram
115	/// the iiac-perf variant builds on the hot path, then render the
116	/// identical band table.
117	fn report(name: &str, rec: &ArrayRecorder<Vec<u64>>, as_ticks: bool) {
118	    #[allow(clippy::unwrap_used)]
119	    // OK: bounds are valid constants (1 ≤ low < high, sigfig 3 ≤ 5)
120	    let mut hist = Histogram::<u64>::new_with_bounds(1, HIST_HIGH, 3).unwrap();
121	    for &d in rec.deltas() {
122	        #[allow(clippy::unwrap_used)]
123	        // OK: value clamped into the histogram's bounds
124	        hist.record(d.clamp(1, HIST_HIGH)).unwrap();
125	    }
126	    band_table::render("tprobe", name, &hist, as_ticks);
127	    if rec.dropped() > 0 {
128	        println!(
129	            "    WARNING: {} deltas dropped (buffer full; raise --cap)",
130	            band_table::fmt_commas(rec.dropped())
131	        );
132	    }
133	}
134	
135	/// Bench entry point: spawn the pinned producer/consumer pair,
136	/// run for `--secs`, then analyze and report.
137	fn main() {
138	    let cfg = match parse_args(std::env::args()) {
139	        Ok(Some(cfg)) => cfg,
140	        Ok(None) => return,
141	        Err(msg) => {
142	            eprintln!("error: {msg}");
143	            std::process::exit(2);
144	        }
145	    };
146	    if let Err(msg) = ticks::check() {
147	        eprintln!("error: {msg}; refusing to run");
148	        std::process::exit(1);
149	    }
150	    // Trigger calibration eagerly so the report doesn't pay for it.
151	    let _ = ticks::ticks_per_ns();
152	
153	    let (req_tx, req_rx) = mpsc::channel::<u64>();
154	    let (resp_tx, resp_rx) = mpsc::channel::<u64>();
155	    let shutdown = Arc::new(AtomicBool::new(false));
156	
157	    let [producer_cpu, consumer_cpu] = cfg.cores;
158	    let cap = cfg.cap;
159	
160	    let producer_shutdown = shutdown.clone();
161	    let producer = thread::spawn(move || {
162	        pin_current(producer_cpu);
163	        let mut probe = make_probe("producer loop", cap);
164	        let mut counter: u64 = 0;
165	        while !producer_shutdown.load(Ordering::Relaxed) {
166	            probe.start();
167	            counter = counter.wrapping_add(1);
168	            if req_tx.send(counter).is_err() {
169	                break;
170	            }
171	            if resp_rx.recv().is_err() {
172	                break;
173	            }
174	            probe.record();
175	        }
176	        probe
177	    });
178	
179	    let consumer = thread::spawn(move || {
180	        pin_current(consumer_cpu);
181	        let mut probe = make_probe("consumer loop", cap);
182	        loop {
183	            probe.start();
184	            let v = match req_rx.recv() {
185	                Ok(v) => v,
186	                Err(_) => break,
187	            };
188	            if resp_tx.send(v).is_err() {
189	                break;
190	            }
191	            probe.record();
192	        }
193	        probe
194	    });
195	
196	    thread::sleep(Duration::from_secs_f64(cfg.secs));
197	    shutdown.store(true, Ordering::Relaxed);
198	
199	    #[allow(clippy::expect_used)]
200	    // OK: propagate a child-thread panic; fail-fast is correct in a bench
201	    let producer_probe = producer.join().expect("producer panicked");
202	    #[allow(clippy::expect_used)]
203	    // OK: propagate a child-thread panic; fail-fast is correct in a bench
204	    let consumer_probe = consumer.join().expect("consumer panicked");
205	
206	    println!(
207	        "tp_pc (2 threads, tprobe ArrayRecorder) [duration={:.1}s]:",
208	        cfg.secs
209	    );
210	    report(
211	        producer_probe.name(),
212	        producer_probe.recorder(),
213	        cfg.as_ticks,
214	    );
215	    report(
216	        consumer_probe.name(),
217	        consumer_probe.recorder(),
218	        cfg.as_ticks,
219	    );
220	}
221

