209	    let s = format!("{n:.decimals$}");
210	    let (sign, body) = match s.strip_prefix('-') {
211	        Some(rest) => ("-", rest),
212	        None => ("", s.as_str()),
213	    };
214	    let (int_part, frac_part) = match body.find('.') {
215	        Some(i) => (&body[..i], &body[i..]),
216	        None => (body, ""),
217	    };
218	    let int_commas = match int_part.parse::<u64>() {
219	        Ok(n) => fmt_commas(n),
220	        // Non-finite values format as "inf"/"NaN" — no integer
221	        // part to comma-group; pass the text through as-is.
222	        Err(_) => int_part.to_string(),
223	    };
224	    format!("{sign}{int_commas}{frac_part}")
225	}
